     6→import { createCheckoutSession } from '../utils/api';
     7→import { useTranslation } from 'react-i18next';
     8→import './PricingPage.css';
     9→
    10→// Plan metadata — only non-translatable values here
    11→const PLAN_META = [
    12→  { id: 'free',     price: 0,  featureCount: 5, lockedCount: 5, hasBadge: false, highlight: false, priceId: null },
    13→  { id: 'pro',      price: 29, featureCount: 7, lockedCount: 0, hasBadge: true,  highlight: true,  priceId: process.env.REACT_APP_STRIPE_PRO_PRICE_ID },
    14→  { id: 'business', price: 79, featureCount: 7, lockedCount: 0, hasBadge: true,  highlight: false, priceId: process.env.REACT_APP_STRIPE_BUSINESS_PRICE_ID },
    15→];
    16→
    17→// Comparison row value keys (text values that need translation use a key, icons/numbers stay as-is)
    18→const COMPARISON_ROWS = [
    19→  { idx: 0, free: '3/day', pro: 'unlimited', business: 'unlimited' },
    20→  { idx: 1, free: '✅', pro: '✅', business: '✅' },
    21→  { idx: 2, free: '✅', pro: '✅', business: '✅' },
    22→  { idx: 3, free: '❌', pro: '✅', business: '✅' },
    23→  { idx: 4, free: '❌', pro: '✅', business: '✅' },
    24→  { idx: 5, free: '❌', pro: '✅', business: '✅' },
    25→  { idx: 6, free: '❌', pro: '✅', business: '✅' },
    26→  { idx: 7, free: '❌', pro: '✅', business: '✅' },
    27→  { idx: 8, free: '1', pro: '1', business: '10' },
    28→  { idx: 9, free: 'email', pro: 'priority', business: 'dedicated' },
    29→];
    30→
    31→const FAQ_COUNT = 6;
    32→
    33→const fadeUp = {
    34→  hidden: { opacity: 0, y: 20 },
    35→  visible: { opacity: 1, y: 0 },
    36→};
    37→
    38→const stagger = {
    39→  hidden: {},
    40→  visible: { transition: { staggerChildren: 0.1 } },
    41→};
    42→
    43→export default function PricingPage() {
    44→  const { currentUser } = useAuth();
    45→  const { subscription } = useSubscription();
    46→  const navigate = useNavigate();
    47→  const { t } = useTranslation();
    48→  const [loadingPlan, setLoadingPlan] = useState(null);
    49→  const [error, setError] = useState('');
    50→
    51→  async function handlePlanSelect(plan) {
    52→    if (plan.id === 'free') {
    53→      navigate('/auth?mode=register');
    54→      return;
    55→    }
    56→
    57→    if (!currentUser) {
    58→      navigate('/auth?mode=register');
    59→      return;
    60→    }
    61→
    62→    if (!plan.priceId || plan.priceId === 'undefined') {
    63→      setError('Payment system is not configured yet. Please add Stripe price IDs to your environment variables.');
    64→      return;
    65→    }
    66→
    67→    setError('');
    68→    setLoadingPlan(plan.id);
    69→    try {
    70→      const { url } = await createCheckoutSession(plan.priceId);
    71→      window.location.href = url;
    72→    } catch (err) {
    73→      setError(err.message || 'Failed to start checkout. Please try again.');
    74→    }
    75→    setLoadingPlan(null);
    76→  }
    77→
    78→  function getPlanCta(plan) {
    79→    if (!currentUser && plan.id !== 'free') return t('pricing.signUpToStart', { defaultValue: 'Sign Up to Start' });
    80→    if (subscription === plan.id) return t('pricing.currentPlan', { defaultValue: '✅ Current Plan' });
    81→    if (plan.id === 'free' && subscription !== 'free') return t('pricing.downgrade', { defaultValue: 'Downgrade' });
    82→    return t(`pricing.plan.${plan.id}.cta`);
    83→  }
    84→
    85→  function translateVal(val) {
    86→    if (val === 'unlimited') return t('pricing.comparison.unlimited', { defaultValue: 'Unlimited' });
    87→    if (val === 'email')     return t('pricing.comparison.email',     { defaultValue: 'Email' });
    88→    if (val === 'priority')  return t('pricing.comparison.priority',  { defaultValue: 'Priority' });
    89→    if (val === 'dedicated') return t('pricing.comparison.dedicated', { defaultValue: 'Dedicated' });
    90→    return val;
    91→  }
    92→
    93→  return (
    94→    <div className="page">
    95→      <div className="pricing">
    96→        {/* Hero */}
    97→        <motion.div
    98→          className="pricing__hero container"
    99→          initial={{ opacity: 0, y: 30 }}
   100→          animate={{ opacity: 1, y: 0 }}
   101→          transition={{ duration: 0.6 }}
   102→        >
   103→          <span className="badge badge-primary">
   104→            {t('pricing.hero.badge', { defaultValue: 'Simple, Transparent Pricing' })}
   105→          </span>
   106→          <h1 className="pricing__title">
   107→            {t('pricing.hero.titlePre', { defaultValue: 'Choose Your' })}{' '}
   108→            <span className="gradient-text">{t('pricing.hero.titleHighlight', { defaultValue: 'Growth Plan' })}</span>
   109→          </h1>
   110→          <p className="pricing__subtitle">
   111→            {t('pricing.hero.subtitle', { defaultValue: "Start free. Upgrade when you're ready. No contracts, cancel anytime." })}
   112→          </p>
   113→        </motion.div>
   114→
   115→        {error && (
   116→          <div className="container">
   117→            <div className="alert alert-warning" style={{ marginBottom: '2rem' }}>
   118→              ⚠️ {error}
   119→            </div>
   120→          </div>
   121→        )}
   122→
   123→        {/* Plans */}
   124→        <div className="container">
   125→          <motion.div
   126→            className="pricing__plans"
   127→            initial="hidden"
   128→            animate="visible"
   129→            variants={stagger}
   130→          >
   131→            {PLAN_META.map((plan) => {
   132→              const features = Array.from({ length: plan.featureCount }, (_, i) =>
   133→                t(`pricing.plan.${plan.id}.feature.${i}`)
   134→              );
   135→              const locked = Array.from({ length: plan.lockedCount }, (_, i) =>
   136→                t(`pricing.plan.${plan.id}.locked.${i}`)
   137→              );
   138→
   139→              return (
   140→                <motion.div
   141→                  key={plan.id}
   142→                  className={`pricing__plan ${plan.highlight ? 'pricing__plan--highlight' : ''} ${subscription === plan.id ? 'pricing__plan--current' : ''}`}
   143→                  variants={fadeUp}
   144→                  whileHover={{ y: plan.highlight ? -8 : -4 }}
   145→                  transition={{ type: 'spring', stiffness: 300, damping: 25 }}
   146→                >
   147→                  {plan.highlight && <div className="pricing__plan-glow" />}
   148→
   149→                  {plan.hasBadge && subscription !== plan.id && (
   150→                    <div className="pricing__plan-badge">
   151→                      {t(`pricing.plan.${plan.id}.badge`)}
   152→                    </div>
   153→                  )}
   154→
   155→                  {subscription === plan.id && (
   156→                    <div className="pricing__plan-badge pricing__plan-badge--current">
   157→                      {t('pricing.currentPlan', { defaultValue: '✅ Current Plan' })}
   158→                    </div>
   159→                  )}
   160→
   161→                  <div className="pricing__plan-header">
   162→                    <h2 className="pricing__plan-name">{t(`pricing.plan.${plan.id}.name`)}</h2>
   163→                    <p className="pricing__plan-desc">{t(`pricing.plan.${plan.id}.desc`)}</p>
   164→                  </div>
   165→
   166→                  <div className="pricing__plan-price">
   167→                    <span className="pricing__plan-amount">${plan.price}</span>
   168→                    <div className="pricing__plan-period">
   169→                      {plan.price === 0
   170→                        ? t('pricing.forever', { defaultValue: 'forever free' })
   171→                        : t('pricing.month', { defaultValue: '/month' })}
   172→                    </div>
   173→                  </div>
   174→
   175→                  <button
   176→                    className={`btn ${plan.highlight ? 'btn-primary' : 'btn-secondary'} pricing__plan-cta`}
   177→                    onClick={() => handlePlanSelect(plan)}
   178→                    disabled={subscription === plan.id || loadingPlan === plan.id}
   179→                  >
   180→                    {loadingPlan === plan.id ? (
   181→                      <><span className="spinner" /> {t('pricing.processing', { defaultValue: 'Processing...' })}</>
   182→                    ) : (
   183→                      getPlanCta(plan)
   184→                    )}
   185→                  </button>
   186→
   187→                  <div className="pricing__features">
   188→                    {features.map((f) => (
   189→                      <div key={f} className="pricing__feature pricing__feature--included">
   190→                        <span className="pricing__feature-icon">✅</span>
   191→                        <span>{f}</span>
   192→                      </div>
   193→                    ))}
   194→                    {locked.map((f) => (
   195→                      <div key={f} className="pricing__feature pricing__feature--locked">
   196→                        <span className="pricing__feature-icon">🔒</span>
   197→                        <span>{f}</span>
   198→                      </div>
   199→                    ))}
   200→                  </div>
   201→                </motion.div>
   202→              );
   203→            })}
   204→          </motion.div>
   205→        </div>
   206→
   207→        {/* Comparison table */}
   208→        <div className="container">
   209→          <motion.div
   210→            className="pricing__comparison"
   211→            initial={{ opacity: 0, y: 30 }}
   212→            whileInView={{ opacity: 1, y: 0 }}
   213→            viewport={{ once: true, margin: '-80px' }}
   214→            transition={{ duration: 0.6 }}
   215→          >
   216→            <h2 className="pricing__comparison-title">
   217→              {t('pricing.comparison.title', { defaultValue: 'Full Feature Comparison' })}
   218→            </h2>
   219→            <div className="pricing__table-wrap">
   220→              <table className="pricing__table">
   221→                <thead>
   222→                  <tr>
   223→                    <th>{t('pricing.comparison.featureCol', { defaultValue: 'Feature' })}</th>
   224→                    <th>{t('pricing.plan.free.name', { defaultValue: 'Free' })}</th>
   225→                    <th className="pricing__th--highlight">Pro</th>
   226→                    <th>{t('pricing.plan.business.name', { defaultValue: 'Business' })}</th>
   227→                  </tr>
   228→                </thead>
   229→                <tbody>
   230→                  {COMPARISON_ROWS.map((row) => (
   231→                    <tr key={row.idx}>
   232→                      <td>{t(`pricing.comparison.row.${row.idx}`)}</td>
   233→                      <td>{translateVal(row.free)}</td>
   234→                      <td className="pricing__td--highlight">{translateVal(row.pro)}</td>
   235→                      <td>{translateVal(row.business)}</td>
   236→                    </tr>
   237→                  ))}
   238→                </tbody>
   239→              </table>
   240→            </div>
   241→          </motion.div>
   242→        </div>
   243→
   244→        {/* FAQ */}
   245→        <div className="container pricing__faq">
   246→          <h2 className="pricing__comparison-title">
   247→            {t('pricing.faq.title', { defaultValue: 'Frequently Asked Questions' })}
   248→          </h2>
   249→          <div className="pricing__faq-grid">
   250→            {Array.from({ length: FAQ_COUNT }, (_, i) => (
   251→              <div key={i} className="pricing__faq-item">
   252→                <h4>{t(`pricing.faq.${i}.q`)}</h4>
   253→                <p>{t(`pricing.faq.${i}.a`)}</p>
   254→              </div>
   255→            ))}
   256→          </div>
   257→        </div>
   258→
   259→        {/* CTA */}
   260→        <div className="container pricing__bottom-cta">
   261→          <motion.div
   262→            className="pricing__cta-card"
   263→            initial={{ opacity: 0, y: 20 }}
   264→            whileInView={{ opacity: 1, y: 0 }}
   265→            viewport={{ once: true }}
   266→          >
   267→            <h2>
   268→              {t('pricing.cta.titlePre', { defaultValue: 'Ready to' })}{' '}
   269→              <span className="gradient-text">{t('pricing.cta.titleHighlight', { defaultValue: 'Get Started?' })}</span>
   270→            </h2>
   271→            <p>{t('pricing.cta.subtitle', { defaultValue: 'Join thousands of marketers, founders, and agencies growing with AI.' })}</p>
   272→            <Link to="/auth?mode=register" className="btn btn-primary btn-lg">
   273→              {t('pricing.cta.btn', { defaultValue: 'Start Free Today →' })}
   274→            </Link>
   275→          </motion.div>
   276→        </div>
   277→      </div>
   278→    </div>
   279→  );
   280→}
