     1→import React from 'react';
     2→import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
     3→import { AuthProvider } from './context/AuthContext';
     4→import { SubscriptionProvider } from './context/SubscriptionContext';
