     9→import './App.css';
    10→
    11→import LandingPage from './pages/LandingPage';
    12→import AuthPage from './pages/AuthPage';
    13→import Dashboard from './pages/Dashboard';
    14→import CategoryPage from './pages/CategoryPage';
    15→import PricingPage from './pages/PricingPage';
    16→import SettingsPage from './pages/SettingsPage';
    17→
    18→import { useLocation } from "react-router-dom";
    19→import { useEffect } from "react";
    20→import ReactGA from "react-ga4";
    21→
    22→function AnalyticsTracker() {
    23→  const location = useLocation();
    24→
    25→  useEffect(() => {
    26→    ReactGA.send({
    27→      hitType: "pageview",
    28→      page: location.pathname + location.search,
    29→    });
    30→  }, [location]);
    31→
    32→  return null;
    33→}
    34→
    35→
    36→function AppLayout({ children, hideFooter }) {
    37→  return (
    38→    <>
    39→      <Navbar />
    40→      <main style={{ flex: 1 }}>{children}</main>
    41→      {!hideFooter && <Footer />}
    42→    </>
    43→  );
    44→}
    45→
    46→
    47→export default function App() {
    48→  return (
    49→    <Router>
    50→      <AnalyticsTracker />
    51→      <AuthProvider>
    52→        <SubscriptionProvider>
    53→          <Routes>
    54→            {/* Public routes */}
    55→            <Route
    56→              path="/"
    57→              element={
    58→                <AppLayout>
    59→                  <LandingPage />
    60→                </AppLayout>
    61→              }
    62→            />
    63→            <Route
    64→              path="/auth"
    65→              element={<AuthPage />}
    66→            />
    67→            <Route
    68→              path="/pricing"
    69→              element={
    70→                <AppLayout>
    71→                  <PricingPage />
    72→                </AppLayout>
    73→              }
    74→            />
    75→
    76→            {/* Protected routes */}
    77→            <Route
    78→              path="/dashboard"
    79→              element={
    80→                <ProtectedRoute>
    81→                  <AppLayout>
    82→                    <Dashboard />
    83→                  </AppLayout>
    84→                </ProtectedRoute>
    85→              }
    86→            />
    87→            <Route
    88→              path="/category/:categoryId"
    89→              element={
    90→                <ProtectedRoute>
    91→                  <AppLayout hideFooter>
    92→                    <CategoryPage />
    93→                  </AppLayout>
    94→                </ProtectedRoute>
    95→              }
    96→            />
    97→            <Route
    98→              path="/settings"
    99→              element={
   100→                <ProtectedRoute>
   101→                  <AppLayout>
   102→                    <SettingsPage />
   103→                  </AppLayout>
   104→                </ProtectedRoute>
   105→              }
   106→            />
   107→
   108→            {/* Catch all */}
   109→            <Route path="*" element={<Navigate to="/" replace />} />
   110→          </Routes>
   111→        </SubscriptionProvider>
   112→      </AuthProvider>
   113→    </Router>
   114→  );
   115→}
